import{_ as s,g as t,h as n,U as m}from"./chunks/vitepress-theme-teek.CpQ8F4CP.js";const h=JSON.parse('{"title":"当“实现”不再是壁垒：工程师如何构建产品 Sense？","description":"摘要总结：当 AI 让代码生成的边际成本趋近于零，“技术实现”不再是不可逾越的壁垒，“产品洞察”能构筑起新的核心护城河。本文拒绝玄学，将抽象的 产品 Sense 解构为三个核心数学公式，并提供一套基于“逆向工程”的刻意练习指南，助力开发者在算力过剩的时代，完成从“代码工匠”到“价值创造者”的认知跃迁。","frontmatter":{"date":"2025-10-23T16:05:50.000Z","title":"当“实现”不再是壁垒：工程师如何构建产品 Sense？","description":"摘要总结：当 AI 让代码生成的边际成本趋近于零，“技术实现”不再是不可逾越的壁垒，“产品洞察”能构筑起新的核心护城河。本文拒绝玄学，将抽象的 产品 Sense 解构为三个核心数学公式，并提供一套基于“逆向工程”的刻意练习指南，助力开发者在算力过剩的时代，完成从“代码工匠”到“价值创造者”的认知跃迁。","sticky":1,"top":true,"categories":["产品 Sense","AI"],"coverImg":"https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/cover/product_sense_bg.png","permalink":"/product-sense/engineer-build-product-sense"},"headers":[],"relativePath":"product-sense/engineer-build-product-sense.md","filePath":"10.产品 Sense/02.新 T 型人/21.工程师如何构建产品 Sense.md"}'),i={name:"product-sense/engineer-build-product-sense.md"};function o(l,a,e,r,p,d){return n(),t("div",null,[...a[0]||(a[0]=[m('<h1 id="当-实现-不再是壁垒-工程师如何构建产品-sense" tabindex="-1">当“实现”不再是壁垒：工程师如何构建产品 Sense？ <a class="header-anchor" href="#当-实现-不再是壁垒-工程师如何构建产品-sense" aria-label="Permalink to “当“实现”不再是壁垒：工程师如何构建产品 Sense？”">​</a></h1><blockquote><p><strong>摘要总结</strong>：当 AI 让代码生成的边际成本趋近于零，“技术实现”不再是不可逾越的壁垒，“产品洞察”能构筑起新的核心护城河。本文拒绝玄学，将抽象的 产品 Sense 解构为三个核心数学公式，并提供一套基于“逆向工程”的刻意练习指南，助力开发者在算力过剩的时代，完成从“代码工匠”到“价值创造者”的认知跃迁。</p></blockquote><h2 id="_1-引言" tabindex="-1">1. 引言 <a class="header-anchor" href="#_1-引言" aria-label="Permalink to “1. 引言”">​</a></h2><p>在很长一段时间里，产品 Sense（产品感） 被视为一种玄学。它似乎是乔布斯式的灵光一现，或是张小龙式的“独断专行”。</p><p>但对于大多数工程师、产品经理乃至独立开发者而言，将能力寄托于“天赋”是危险的。我认为，<strong>产品 Sense 并非不可捉摸的黑魔法，而是一套经过高频训练后内化为本能的思维算法</strong>。 就像资深程序员看到一段代码就能嗅出 &quot;Code Smell&quot;（代码异味），资深产品人也能在瞬间判断一个需求是“真痛点”还是“伪需求”。</p><p>一个成功的产品决策，往往发生在三个维度的交汇点：</p><ul><li><strong>用户价值洞察（User Value Insight）：</strong>不仅听懂用户说“想要更快的马”，更能洞察他其实“想更快到达目的地”。</li><li><strong>商业可行性（Business Viability）：</strong>不仅能做出来，还能算得过账。像 Dropbox 早期利用病毒式裂变降低获客成本，就是商业嗅觉的体现。</li><li><strong>技术可实现性（Technical Feasibility）：</strong>在“完美的架构”和“明天就能上线”之间找到平衡。ChatGPT 的爆发，正是技术积累终于跨过了“可用性阈值”的临界点。</li></ul><p>产品 Sense 是产品经理、设计师乃至创业者经常被提及、却也难以量化的能力之一。它并非玄学，而是一套可拆解、可训练、可迭代的思维模型：<strong>在信息不完整、目标模糊、资源受限的情况下，依然能快速判断「做什么」与「不做什么」，并让用户愿意为之买单或停留</strong>。</p><h2 id="_2-解构产品-sense-的数学之美" tabindex="-1">2. 解构产品 Sense 的数学之美 <a class="header-anchor" href="#_2-解构产品-sense-的数学之美" aria-label="Permalink to “2. 解构产品 Sense 的数学之美”">​</a></h2><p>如果把产品 Sense 仅仅看作是“灵光一现”的艺术，那它就是不可复制的黑盒。作为工程师，我们更习惯于透过现象探寻底层的运行规律。</p><p>事实上，那些看似玄妙的直觉判断，往往是潜意识在极短时间内完成的高维计算。为了让这个抽象概念变得可解构、可训练，我尝试用理性的数学语言来重构感性的产品直觉，将其提炼为以下三个核心公式。</p><h3 id="_2-1-极简杠杆公式-寻找-roi-的最大解" tabindex="-1">2.1. 极简杠杆公式：寻找 ROI 的最大解 <a class="header-anchor" href="#_2-1-极简杠杆公式-寻找-roi-的最大解" aria-label="Permalink to “2.1. 极简杠杆公式：寻找 ROI 的最大解”">​</a></h3><div class="note custom-block"><p class="title note-title custom-block-title">NOTE</p><p><strong>核心逻辑：</strong>卓越的产品嗅觉（产品 Sense）本质上是一种<strong>寻找“高杠杆解”的能力，对投入产出比（ROI）极致敏感</strong>。它要求我们<strong>敏锐地发现那些 “价值极高，但实现较低” 的低垂机会（Low Hanging Fruits），并果断放弃那些 “价值低又很难做” 的伪需求</strong>（看似美好，实则陷入技术泥潭）。</p><p><strong>适用场景：</strong>技术选型决策、Feature 排期优先级、MVP 边界界定。</p></div><p>对于技术背景的开发者，最大的陷阱往往是“对过度设计的迷恋” 与 “为了技术而技术的自我感动”。因为掌握了某个新技术，就强行创造一个需求，但好的 Product Sense 其实是投入产出比（ROI）的直觉：</p><p><span class="katex-display"><span class="katex"><span class="katex-mathml"><math><semantics><mrow><mrow><mi mathvariant="bold">P</mi><mi mathvariant="bold">r</mi><mi mathvariant="bold">o</mi><mi mathvariant="bold">d</mi><mi mathvariant="bold">u</mi><mi mathvariant="bold">c</mi><mi mathvariant="bold">t</mi><mtext> </mtext><mi mathvariant="bold">S</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">n</mi><mi mathvariant="bold">s</mi><mi mathvariant="bold">e</mi></mrow><mspace width="0.277778em"></mspace><mo>=</mo><mspace width="0.277778em"></mspace><mfrac><mrow><mrow><mi mathvariant="bold">U</mi><mi mathvariant="bold">s</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">r</mi><mtext> </mtext><mi mathvariant="bold">V</mi><mi mathvariant="bold">a</mi><mi mathvariant="bold">l</mi><mi mathvariant="bold">u</mi><mi mathvariant="bold">e</mi></mrow></mrow><mrow><mrow><mi mathvariant="bold">C</mi><mi mathvariant="bold">o</mi><mi mathvariant="bold">m</mi><mi mathvariant="bold">p</mi><mi mathvariant="bold">l</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">x</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">t</mi><mi mathvariant="bold">y</mi></mrow></mrow></mfrac></mrow><annotation encoding="application/x-tex">\\mathbf{Product\\ Sense} \\; = \\; \\frac{\\mathbf{User\\ Value}}{\\mathbf{Complexity}} </annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:1.37144em;"></span><span class="strut bottom" style="height:2.25188em;vertical-align:-0.8804400000000001em;"></span><span class="base displaystyle textstyle uncramped"><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">P</span><span class="mord mathbf">r</span><span class="mord mathbf">o</span><span class="mord mathbf">d</span><span class="mord mathbf">u</span><span class="mord mathbf">c</span><span class="mord mathbf">t</span><span class="mord mspace"> </span><span class="mord mathbf">S</span><span class="mord mathbf">e</span><span class="mord mathbf">n</span><span class="mord mathbf">s</span><span class="mord mathbf">e</span></span><span class="mord mspace thickspace"></span><span class="mrel">=</span><span class="mord mspace thickspace"></span><span class="mord reset-textstyle displaystyle textstyle uncramped"><span class="sizing reset-size5 size5 reset-textstyle textstyle uncramped nulldelimiter"></span><span class="mfrac"><span class="vlist"><span style="top:0.6860000000000002em;"><span class="fontsize-ensurer reset-size5 size5"><span style="font-size:0em;">​</span></span><span class="reset-textstyle textstyle cramped"><span class="mord textstyle cramped"><span class="mord textstyle cramped"><span class="mord mathbf">C</span><span class="mord mathbf">o</span><span class="mord mathbf">m</span><span class="mord mathbf">p</span><span class="mord mathbf">l</span><span class="mord mathbf">e</span><span class="mord mathbf">x</span><span class="mord mathbf">i</span><span class="mord mathbf">t</span><span class="mord mathbf" style="margin-right:0.01597em;">y</span></span></span></span></span><span style="top:-0.22999999999999998em;"><span class="fontsize-ensurer reset-size5 size5"><span style="font-size:0em;">​</span></span><span class="reset-textstyle textstyle uncramped frac-line"></span></span><span style="top:-0.677em;"><span class="fontsize-ensurer reset-size5 size5"><span style="font-size:0em;">​</span></span><span class="reset-textstyle textstyle uncramped"><span class="mord textstyle uncramped"><span class="mord textstyle uncramped"><span class="mord mathbf">U</span><span class="mord mathbf">s</span><span class="mord mathbf">e</span><span class="mord mathbf">r</span><span class="mord mspace"> </span><span class="mord mathbf" style="margin-right:0.01597em;">V</span><span class="mord mathbf">a</span><span class="mord mathbf">l</span><span class="mord mathbf">u</span><span class="mord mathbf">e</span></span></span></span></span><span class="baseline-fix"><span class="fontsize-ensurer reset-size5 size5"><span style="font-size:0em;">​</span></span>​</span></span></span><span class="sizing reset-size5 size5 reset-textstyle textstyle uncramped nulldelimiter"></span></span></span></span></span></span></p><ul><li><strong>分子——用户价值（User Value）：</strong> <strong>痛点烈度 × 覆盖广度</strong>不仅仅是“这个问题痛不痛”，而是要量化思考：这是一个高频刚需，还是低频痒点？解决它能为业务带来多大的增量（留存、转化或效率提升）？</li><li><strong>分母——实现复杂度（Complexity）：</strong> <strong>开发成本 + 维护税</strong>复杂度不仅是 Coding 的时间，更包含未来的维护成本、系统熵增以及用户认知的负担。全栈的智慧在于：用最简单的技术栈（Low Complexity），去撬动最大的业务价值。敢于在非核心功能上使用“笨办法”，是为了在核心体验上以此换取“极致体验”。</li></ul><h3 id="_2-2-洞察力公式-理智与情感的共舞" tabindex="-1">2.2. 洞察力公式：理智与情感的共舞 <a class="header-anchor" href="#_2-2-洞察力公式-理智与情感的共舞" aria-label="Permalink to “2.2. 洞察力公式：理智与情感的共舞”">​</a></h3><div class="note custom-block"><p class="title note-title custom-block-title">NOTE</p><p>核心逻辑：<strong>同理心提供&quot;方向&quot;，批判性思维提供&quot;导航&quot;</strong></p><ul><li><strong>同理心告诉你&quot;用户很痛苦&quot;</strong>，<em><strong>批判性思维告诉你&quot;痛苦的根源是什么&quot;</strong></em>。</li><li><strong>同理心告诉你&quot;用户想要什么&quot;</strong>，<em><strong>批判性思维告诉你&quot;为什么想要&quot;和&quot;有没有更好的解决方案&quot;</strong></em>。</li></ul><p><strong>适用场景：</strong>需求分析、用户调研、产品定位、功能设计、A/B 测试方案设计。</p></div><p>仅有同理心，产品容易沦为“臃肿的许愿池”（用户要什么给什么，导致产品臃肿）；仅有批判性思维，产品容易变成“冰冷的逻辑机器”（数据看似完美，却缺乏打动人心的人性温度）。因此，产品 Sense 本质上也是同理心与批判性思维的结合：</p><blockquote><p>例如，用户抱怨&quot;App 太复杂&quot;，同理心让你感受到用户的挫败感，批判性思维让你追问：是功能太多？还是导航不清晰？还是学习成本太高？——不同的根源需要不同的解决方案。</p></blockquote><p><span class="katex-display"><span class="katex"><span class="katex-mathml"><math><semantics><mrow><mrow><mi mathvariant="bold">P</mi><mi mathvariant="bold">r</mi><mi mathvariant="bold">o</mi><mi mathvariant="bold">d</mi><mi mathvariant="bold">u</mi><mi mathvariant="bold">c</mi><mi mathvariant="bold">t</mi><mtext> </mtext><mi mathvariant="bold">S</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">n</mi><mi mathvariant="bold">s</mi><mi mathvariant="bold">e</mi></mrow><mspace width="0.277778em"></mspace><mo>=</mo><mspace width="0.277778em"></mspace><mrow><mi mathvariant="bold">E</mi><mi mathvariant="bold">m</mi><mi mathvariant="bold">p</mi><mi mathvariant="bold">a</mi><mi mathvariant="bold">t</mi><mi mathvariant="bold">h</mi><mi mathvariant="bold">y</mi></mrow><mspace width="0.277778em"></mspace><mo>×</mo><mspace width="0.277778em"></mspace><mrow><mi mathvariant="bold">C</mi><mi mathvariant="bold">r</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">t</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">c</mi><mi mathvariant="bold">a</mi><mi mathvariant="bold">l</mi><mtext> </mtext><mi mathvariant="bold">T</mi><mi mathvariant="bold">h</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">n</mi><mi mathvariant="bold">k</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">n</mi><mi mathvariant="bold">g</mi></mrow></mrow><annotation encoding="application/x-tex">\\mathbf{Product\\ Sense} \\; = \\; \\mathbf{Empathy} \\; \\times \\; \\mathbf{Critical\\ Thinking} </annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.69444em;"></span><span class="strut bottom" style="height:0.8888799999999999em;vertical-align:-0.19444em;"></span><span class="base displaystyle textstyle uncramped"><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">P</span><span class="mord mathbf">r</span><span class="mord mathbf">o</span><span class="mord mathbf">d</span><span class="mord mathbf">u</span><span class="mord mathbf">c</span><span class="mord mathbf">t</span><span class="mord mspace"> </span><span class="mord mathbf">S</span><span class="mord mathbf">e</span><span class="mord mathbf">n</span><span class="mord mathbf">s</span><span class="mord mathbf">e</span></span><span class="mord mspace thickspace"></span><span class="mrel">=</span><span class="mord mspace thickspace"></span><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">E</span><span class="mord mathbf">m</span><span class="mord mathbf">p</span><span class="mord mathbf">a</span><span class="mord mathbf">t</span><span class="mord mathbf">h</span><span class="mord mathbf" style="margin-right:0.01597em;">y</span></span><span class="mord mspace thickspace"></span><span class="mbin">×</span><span class="mord mspace thickspace"></span><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">C</span><span class="mord mathbf">r</span><span class="mord mathbf">i</span><span class="mord mathbf">t</span><span class="mord mathbf">i</span><span class="mord mathbf">c</span><span class="mord mathbf">a</span><span class="mord mathbf">l</span><span class="mord mspace"> </span><span class="mord mathbf">T</span><span class="mord mathbf">h</span><span class="mord mathbf">i</span><span class="mord mathbf">n</span><span class="mord mathbf">k</span><span class="mord mathbf">i</span><span class="mord mathbf">n</span><span class="mord mathbf" style="margin-right:0.01597em;">g</span></span></span></span></span></span></p><p>注意，这里是<strong>乘法关系</strong>而不是加法，意味着任何一个为零，整个结果都是零。只有同理心但缺乏批判性思维，会做出&quot;用户要什么就给什么&quot;的平庸产品；只有批判性思维但缺乏同理心，会做出&quot;技术上完美但用户不买账&quot;的产品。</p><ul><li><p><strong>同理心 (Empathy)：</strong> <em>感知用户真实感受的能力</em>。同理心不是&quot;我理解用户&quot;，而是&quot;我能<strong>变成</strong>用户&quot;。这意味着：</p><ul><li><strong>情境代入：</strong>能够切换到用户的真实使用场景。例如，设计外卖 App 时，不是在办公室想象&quot;用户想要什么功能&quot;，而是站在雨夜路边、手机电量 10% 的真实场景中思考。</li><li><strong>情绪捕捉：</strong>能够识别用户未说出口的情绪。用户抱怨&quot;页面加载慢&quot;，背后的情绪可能是&quot;我饿得不行了，还要等多久？&quot;——解决方案不只是优化代码，更可能是优化&quot;等待时的体验&quot;（比如显示预计时间、播放动画）。</li><li><strong>认知对齐：</strong>不预设用户很聪明。用户不会像你一样熟悉产品，他们会在你意想不到的地方卡住。例如，注册页面的&quot;密码强度&quot;指示器，用户可能根本看不懂那些颜色代表什么。</li><li><strong>反面案例：</strong>某电商 App 在购物车页面放置了 20 个功能入口，产品经理觉得&quot;功能很全&quot;，但用户只想要一个&quot;快速结算&quot;按钮。</li></ul></li><li><p><strong>批判性思维 (Critical Thinking)：</strong> <em>透过现象看本质的能力</em>。批判性思维不是&quot;质疑一切&quot;，而是&quot;追问为什么&quot;。这意味着：</p><ul><li><strong>需求挖掘：</strong>用户说&quot;想要&quot;的不一定是他们&quot;需要&quot;的。经典的例子：用户说&quot;我要一匹更快的马&quot;，背后的需求是&quot;更快到达目的地&quot;——解决方案可能是汽车、火车、飞机，而不是训练更快的马。</li><li><strong>数据解读：</strong>能够区分&quot;相关性&quot;和&quot;因果关系&quot;。数据显示&quot;使用某功能的用户留存率更高&quot;，但究竟是&quot;功能带来留存&quot;还是&quot;高留存用户恰好用了这个功能&quot;？需要进一步验证。</li><li><strong>假设挑战：</strong>对每个功能假设都要问&quot;如果不做会怎样？&quot;。例如，增加&quot;每日签到&quot;功能前，先问：用户不签到的损失是什么？如果签到带来的价值不足以改变用户行为，那就是伪需求。 <strong>实际案例：</strong>Airbnb 早期发现用户不愿预订，不是因为价格或房源，而是因为&quot;信任陌生房东&quot;。于是他们投入大量精力做&quot;房东验证&quot;&quot;真实评价&quot;&quot;照片认证&quot;，而不是优化搜索算法——这就是批判性思维带来的洞察。</li></ul></li></ul><h3 id="_2-3-ai-前沿视角公式-从-功能产品-到-语境构建" tabindex="-1">2.3. AI 前沿视角公式：从“功能产品”到“语境构建” <a class="header-anchor" href="#_2-3-ai-前沿视角公式-从-功能产品-到-语境构建" aria-label="Permalink to “2.3. AI 前沿视角公式：从“功能产品”到“语境构建””">​</a></h3><div class="note custom-block"><p class="title note-title custom-block-title">NOTE</p><p>核心洞察：AI 时代的稀缺资源不再是“生成答案的能力”（模型已经具备），而是“提出正确问题的能力”。Product Sense 的核心<strong>从“设计功能交互”转变为“设计隐性的思维路径”</strong>，我们需要同时具备 翻译官（将模糊需求结构化） 和 架构师（构建智能体工作流） 的双重能力。</p></div><p>AI 模型本身是通用的引擎，我们需要为它设计底盘和方向盘，产品 Sense 在 AI 时代也就包含了新的特征：<strong>定义问题的能力</strong>——能把模糊的人类需求翻译成 AI 能理解的精确指令和环境：</p><p><span class="katex-display"><span class="katex"><span class="katex-mathml"><math><semantics><mrow><mrow><mi mathvariant="bold">P</mi><mi mathvariant="bold">r</mi><mi mathvariant="bold">o</mi><mi mathvariant="bold">d</mi><mi mathvariant="bold">u</mi><mi mathvariant="bold">c</mi><mi mathvariant="bold">t</mi><mtext> </mtext><mi mathvariant="bold">S</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">n</mi><mi mathvariant="bold">s</mi><mi mathvariant="bold">e</mi></mrow><mspace width="0.277778em"></mspace><mo>=</mo><mspace width="0.277778em"></mspace><mrow><mi mathvariant="bold">P</mi><mi mathvariant="bold">r</mi><mi mathvariant="bold">o</mi><mi mathvariant="bold">b</mi><mi mathvariant="bold">l</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">m</mi><mtext> </mtext><mi mathvariant="bold">D</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">f</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">n</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">t</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">o</mi><mi mathvariant="bold">n</mi></mrow><mspace width="0.277778em"></mspace><mo>+</mo><mspace width="0.277778em"></mspace><mrow><mi mathvariant="bold">C</mi><mi mathvariant="bold">o</mi><mi mathvariant="bold">n</mi><mi mathvariant="bold">t</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">x</mi><mi mathvariant="bold">t</mi><mtext> </mtext><mi mathvariant="bold">D</mi><mi mathvariant="bold">e</mi><mi mathvariant="bold">s</mi><mi mathvariant="bold">i</mi><mi mathvariant="bold">g</mi><mi mathvariant="bold">n</mi></mrow></mrow><annotation encoding="application/x-tex">\\mathbf{Product\\ Sense} \\; = \\; \\mathbf{Problem\\ Definition} \\; + \\; \\mathbf{Context\\ Design} </annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.69444em;"></span><span class="strut bottom" style="height:0.8888799999999999em;vertical-align:-0.19444em;"></span><span class="base displaystyle textstyle uncramped"><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">P</span><span class="mord mathbf">r</span><span class="mord mathbf">o</span><span class="mord mathbf">d</span><span class="mord mathbf">u</span><span class="mord mathbf">c</span><span class="mord mathbf">t</span><span class="mord mspace"> </span><span class="mord mathbf">S</span><span class="mord mathbf">e</span><span class="mord mathbf">n</span><span class="mord mathbf">s</span><span class="mord mathbf">e</span></span><span class="mord mspace thickspace"></span><span class="mrel">=</span><span class="mord mspace thickspace"></span><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">P</span><span class="mord mathbf">r</span><span class="mord mathbf">o</span><span class="mord mathbf">b</span><span class="mord mathbf">l</span><span class="mord mathbf">e</span><span class="mord mathbf">m</span><span class="mord mspace"> </span><span class="mord mathbf">D</span><span class="mord mathbf">e</span><span class="mord mathbf" style="margin-right:0.10903em;">f</span><span class="mord mathbf">i</span><span class="mord mathbf">n</span><span class="mord mathbf">i</span><span class="mord mathbf">t</span><span class="mord mathbf">i</span><span class="mord mathbf">o</span><span class="mord mathbf">n</span></span><span class="mord mspace thickspace"></span><span class="mbin">+</span><span class="mord mspace thickspace"></span><span class="mord displaystyle textstyle uncramped"><span class="mord mathbf">C</span><span class="mord mathbf">o</span><span class="mord mathbf">n</span><span class="mord mathbf">t</span><span class="mord mathbf">e</span><span class="mord mathbf">x</span><span class="mord mathbf">t</span><span class="mord mspace"> </span><span class="mord mathbf">D</span><span class="mord mathbf">e</span><span class="mord mathbf">s</span><span class="mord mathbf">i</span><span class="mord mathbf" style="margin-right:0.01597em;">g</span><span class="mord mathbf">n</span></span></span></span></span></span></p><ul><li><strong>定义问题（Problem Definiton）：</strong><ul><li><strong>结构化歧义：</strong>AI 拥有无限的潜力，也伴随着无限的发散。Product Sense 在此处体现为 <strong>“收敛能力”</strong>——能否将一个模糊的业务痛点（如“分析用户情绪”），拆解为一组 AI 可理解、可执行的精准意图。</li><li><strong>工作流架构：</strong>这不仅仅是写出一句完美的 Prompt，更是设计 Agentic Workflow（智能体工作流）的过程。我们需要判断哪些环节利用 LLM 的逻辑推理（概率性），哪些环节必须由传统代码（确定性）来兜底，从而构建出稳定可靠的系统。</li></ul></li><li><strong>语境设计（Context Design）：从“喂数据”到“构建信息场域”</strong><ul><li><strong>无形界面设计：</strong>在 AI 应用中，真正的 UI 往往不是屏幕上的像素，而是看不见的 <strong>Context Window（上下文窗口）</strong>。Product Sense 就是设计这个“无形界面”的艺术——决定让 AI “看到”什么，以及“忽略”什么。</li><li><strong>约束与边界工程：</strong>Product Sense 在这里体现为：我们能否为 AI 构建一个“全知全能”且“专注当下”的上下文环境，使其输出精准且可控。核心挑战是：如何在有限的上下文窗口（Context Window）中，提供最关键的先验知识、约束条件和少样本（Few-Shot）案例，让 AI 在你预设的“语境场”里精准舞蹈，而不是胡乱幻觉。</li></ul></li></ul><h2 id="_3-刻意练习-如何从-凭感觉-到-有直觉" tabindex="-1">3. 刻意练习：如何从“凭感觉”到“有直觉”？ <a class="header-anchor" href="#_3-刻意练习-如何从-凭感觉-到-有直觉" aria-label="Permalink to “3. 刻意练习：如何从“凭感觉”到“有直觉”？”">​</a></h2><p>很多人认为 Sense 是天赋，无法学习，但我坚信<strong>直觉是经验在潜意识里的压缩算法</strong>。我们可以通过以下三个步骤的“刻意练习”来训练这种算法：</p><h3 id="_3-1-建立-预测-验证-的反馈闭环" tabindex="-1">3.1. 建立“预测-验证”的反馈闭环 <a class="header-anchor" href="#_3-1-建立-预测-验证-的反馈闭环" aria-label="Permalink to “3.1. 建立“预测-验证”的反馈闭环”">​</a></h3><p>这是最硬核的训练法，不要只是被动地看数据，要主动做预测。</p><ul><li><strong>练习方法</strong>：在任何新功能上线前（或者观察竞品改版时），在笔记本上写下你的预测。 <ul><li><em>“我赌这个按钮改为红色，点击率会提升 5%。”</em></li><li><em>“我认为竞品推出这个功能是想解决留存问题，但可能会导致用户反感。”</em></li></ul></li><li><strong>复盘</strong>：一周后，看真实数据或市场反馈。如果你猜对了，强化这个直觉。<strong>如果你猜错了，这才是最宝贵的时刻</strong>：去深究为什么？是高估了用户动力？还是低估了操作门槛？</li><li><strong>原理</strong>：大模型的训练依靠 Loss Function（损失函数）来收敛，人的直觉也一样。只有通过不断的“预测失败”，我们的大脑才能修正权重，从而获得更精准的 Sense。</li></ul><h3 id="_3-2-培养-摩擦力日记" tabindex="-1">3.2. 培养“摩擦力日记” <a class="header-anchor" href="#_3-2-培养-摩擦力日记" aria-label="Permalink to “3.2. 培养“摩擦力日记””">​</a></h3><p>很多时候我们对痛点视而不见，是因为我们<strong>习惯了</strong>，要训练产品 Sense，就要恢复对“不舒服”的敏感度。</p><ul><li><p><strong>练习方法</strong>：每天记录 3 个让自己感到“微小不爽”的时刻，无论是使用自家产品还是生活中的琐事。</p><ul><li><em>“在这个 App 复制验证码居然不能自动跳转，还得我手动切回去，好烦。”</em></li><li><em>“这个报错提示说‘网络错误 404’，为什么不直接告诉我‘请检查 Wi-Fi’？”</em></li></ul></li><li><p><strong>进阶</strong>：不只是抱怨，强迫自己构思一个 <strong>“最小改动解”</strong>。</p><ul><li><em>解法：在复制验证码的短信里加一个 Deep Link，一键跳回 App。</em></li></ul></li></ul><h3 id="_3-3-解构-魔法-从惊叹到复刻的逆向工程" tabindex="-1">3.3. 解构“魔法”：从惊叹到复刻的逆向工程 <a class="header-anchor" href="#_3-3-解构-魔法-从惊叹到复刻的逆向工程" aria-label="Permalink to “3.3. 解构“魔法”：从惊叹到复刻的逆向工程”">​</a></h3><div class="note custom-block"><p class="title note-title custom-block-title">NOTE</p><p>四步闭环: <strong>“记录-解剖-重构-沉淀”</strong></p></div><p>当我们遇到一个让自己惊叹的产品（比如初次使用 ChatGPT或沉迷于 Vibe Coding）时，千万不要只停留在消费者的视角感叹“真好用”。那是“魔法”生效的时刻，也是你作为魔术师学徒拆解戏法的最佳时机。</p><p>若想将这种惊叹内化为自己的 Sense，我们需要执行一套完整的逆向工程循环：</p><h4 id="_1-记录-record-捕捉情绪颗粒度" tabindex="-1">（1）记录 (Record)：捕捉情绪颗粒度 <a class="header-anchor" href="#_1-记录-record-捕捉情绪颗粒度" aria-label="Permalink to “（1）记录 (Record)：捕捉情绪颗粒度”">​</a></h4><p>不要等回头再想，要在“惊叹”发生的当下，像捕捉蝴蝶一样捕捉你的情绪：</p><ul><li><strong>截屏/录屏：</strong>记录下那个让你嘴角上扬或瞳孔放大的瞬间（Aha Moment）。</li><li><strong>微观情绪标注：</strong>问自己，“这一秒，为什么我觉得‘爽’？”是因为那个丝滑的转场动画，还是因为文案恰好击中了我的软肋，还是因为它的响应速度快得不可思议？ <ul><li>案例：Linear 的官网之所以让人惊叹，不仅因为设计，更因为当你按 J / K 键时的毫秒级响应，这种“掌控感”是情绪的来源。</li></ul></li></ul><h4 id="_2-解剖-peel-上帝视角的逻辑拆解" tabindex="-1">（2）解剖 (Peel)：上帝视角的逻辑拆解 <a class="header-anchor" href="#_2-解剖-peel-上帝视角的逻辑拆解" aria-label="Permalink to “（2）解剖 (Peel)：上帝视角的逻辑拆解”">​</a></h4><p>切换到产品经理的上帝视角，透过表皮看骨架。思考它做对了哪三件事：</p><ul><li><strong>它满足了哪个层级的需求？</strong>是底层的生理/安全，还是顶层的自我实现/虚荣？它是帮你省了时间，还是帮你杀了时间？</li><li><strong>它极其大胆地“删减”了什么？</strong>伟大的产品往往由它不做什么来定义。TikTok 删减了用户“选择看什么”的权利，直接喂饭；Notion 早期删减了复杂的格式兼容，只保留 Block。</li><li><strong>它的核心增长飞轮是什么？</strong>它是如何让你忍不住想分享给别人的？是利用了你的炫耀欲，还是单纯的互利机制？</li></ul><h4 id="_3-重构-reconstruct-全栈视角的复刻推演" tabindex="-1">（3）重构 (Reconstruct)：全栈视角的复刻推演 <a class="header-anchor" href="#_3-重构-reconstruct-全栈视角的复刻推演" aria-label="Permalink to “（3）重构 (Reconstruct)：全栈视角的复刻推演”">​</a></h4><p>发挥全栈工程师的技术优势，在脑海中（或草稿纸上）尝试重建它。</p><ul><li><strong>技术推演：</strong>为了实现这个丝滑体验，它的前端可能用了什么技术栈？后端是如何处理高并发的？如果你来做，你会怎么设计数据库 Schema？</li><li><strong>成本估算：</strong>它为了这个体验，付出了多大的工程代价？这个代价在商业上划算吗？</li></ul><h4 id="_4-沉淀-crystallize-输出倒逼内化" tabindex="-1">（4）沉淀 (Crystallize)：输出倒逼内化 <a class="header-anchor" href="#_4-沉淀-crystallize-输出倒逼内化" aria-label="Permalink to “（4）沉淀 (Crystallize)：输出倒逼内化”">​</a></h4><p>这是最关键、却最常被忽略的一步。没有输出的思考，就像没有 commit 的代码，随时会丢失。</p><ul><li><p><strong>写一篇“产品验证报告”：</strong>不要只在脑子里想，要写下来。比如尝试写一篇《为什么 X 产品让我欲罢不能？》，强迫自己把模糊的感觉结构化为文字。</p></li><li><p><strong>发起一场“人机辩论” (Initiate a Human-AI Debate)：</strong> 不要急着把观点发给同行，先让 AI 充当你的“红队”也就是“假想敌”。</p><ul><li><strong>第一轮（AI 陪练）：</strong>把自己的分析发给 GPT/Claude，并加上这句 Prompt：“如果你是这个产品的 CEO，请指出我分析中的漏洞，有哪些商业考量或技术限制是我没看到的？” AI 往往能从你忽略的历史背景、隐形成本或竞争格局角度给出惊人的补充。</li><li><strong>第二轮（真人验证）：</strong>带着 AI 完善过的观点，再去社区或同行间交流。你会发现，你的洞察深度已经超越了 90% 的人，而<strong>真人的反馈则能补充 AI 无法触达的“隐秘行业潜规则”或“人性微妙之处”</strong>。</li></ul></li></ul><h2 id="_4-结语-从-如何实现-的焦虑中解放-拥抱-为何而做-的自由" tabindex="-1">4. 结语：从“如何实现”的焦虑中解放，拥抱“为何而做”的自由 <a class="header-anchor" href="#_4-结语-从-如何实现-的焦虑中解放-拥抱-为何而做-的自由" aria-label="Permalink to “4. 结语：从“如何实现”的焦虑中解放，拥抱“为何而做”的自由”">​</a></h2><p>在 AI 时代，代码生成的边际成本正在无限趋近于零。当“实现”不再是不可逾越的壁垒，“洞察”与“品位”便成了新的护城河。</p><p>未来的全栈工程师将不再是 <strong>[前端 + 后端]</strong>，而是 <strong>[技术理解力 x 产品敏锐度]</strong>的化学反应：</p><ul><li><strong>技术</strong>是我们的压舱石，让我们知晓可能性的边界，不至于在天马行空中失重；</li><li><strong>产品 Sense</strong> 是我们的罗盘，让在生成的洪流中锁定航向，不至于在低价值的代码堆里荒废时光。</li></ul><p>产品 Sense 的终点从来不是“不做错的决定”——那是全知视角的奢望。它的终点是<strong>“拥有比别人更短的纠错半径”</strong>：在错误发生时，能以最低的成本感知并修正。</p><p>保持敏锐，保持饥饿，对“用户下一秒的皱眉”心存敬畏。因为算法无法计算“痛点”，而那个皱眉的瞬间，往往就是下一款好产品的起点。</p>',58)])])}const b=s(i,[["render",o]]);export{h as __pageData,b as default};
